return [{
  json: {
    chapter_id: $input.first().json.chapter_id || '',
    action: $input.first().json.action || 'repair_and_review',
    // repair_and_review | manual_publish | reject
    force_publish: $input.first().json.force_publish || false
  }
}];

// Build revision prompt inputs
const chapter = $('Load Chapter').first().json;
const versionAndReviews = $('Load Version & Reviews').all();

let latestVersion = {};
let reviews = [];
let job = {};

for (const item of versionAndReviews) {
  const j = item.json;
  if (j.version_number) latestVersion = j;
  if (j.agent_name) reviews.push(j);
  if (j.job_type) job = j;
}

const writingBrief = {
  chapter: {
    title: chapter.title,
    body_markdown: latestVersion.body_markdown || chapter.body_markdown,
    summary: latestVersion.summary || chapter.summary
  },
  review_reports: reviews.map(r => ({
    agent_name: r.agent_name,
    score: r.score,
    pass: r.pass,
    blocking_issues: r.blocking_issues,
    minor_issues: r.minor_issues,
    recommendations: r.recommendations
  })),
  quality_threshold: chapter.quality_threshold || 85,
  revise_count: job.revise_count || 0,
  project_id: chapter.project_id
};

return [{
  json: {
    chapter_id: chapter.id,
    project_id: chapter.project_id,
    job_id: job.id,
    latest_version: latestVersion,
    writing_brief: writingBrief,
    revise_count: job.revise_count || 0,
    max_revise_count: chapter.max_revise_count || 2
  }
}];

// After revision, re-run lightweight review
const chapter = $('Load Chapter').first().json;
const revision = $('Call Writer Revise').first().json.data;

return [{
  json: {
    chapter_id: chapter.id,
    chapter: revision,
    project_policy: { quality_threshold: chapter.quality_threshold }
  }
}];

// Decide: publish, re-revise, or flag for human
const safetyResult = JSON.parse($input.first().json.choices[0].message.content);
const revisionInput = $('Build Revision Input').first().json;

let decision = 'publish_ready';
if (!safetyResult.pass) {
  decision = 'needs_human_review';
} else if (revisionInput.revise_count >= revisionInput.max_revise_count) {
  decision = 'needs_human_review';
}

return [{
  json: {
    chapter_id: revisionInput.chapter_id,
    project_id: revisionInput.project_id,
    job_id: revisionInput.job_id,
    safety_pass: safetyResult.pass,
    decision: decision,
    message: decision === 'publish_ready'
      ? 'Chapter revised and passed review. Ready for manual publish.'
      : 'Chapter still has issues — needs human review.'
  }
}];

return [{
  json: {
    status: 'complete',
    message: $('Final Decision').first().json.message,
    chapter_id: $('Final Decision').first().json.chapter_id,
    decision: $('Final Decision').first().json.decision
  }
}];
